     * and values are the maximum size of a subset that achieves that XOR sum.
     * Uses dynamic programming based on subset iteration. O(N * 2^N).
     * @param {number[]} arr 
     * @returns {Map<number, number>}
     */
    function generate_xor_sums_map(arr) {
        // Map: XOR_Sum -> Max_Size
        let map = new Map();
        // Initialize with the empty set: XOR sum 0, size 0
        map.set(0, 0); 

        for (const num of arr) {
            // next_map stores results after considering 'num'. Start by copying existing results.
            const next_map = new Map(map); 

            for (const [xor_sum, size] of map.entries()) {
                // Option 2: Include 'num'
                const new_xor_sum = xor_sum ^ num;
                const new_size = size + 1;

                // Update next_map: we want the maximum size for new_xor_sum
                const existing_size = next_map.get(new_xor_sum) || -1;
                if (new_size > existing_size) {
                    next_map.set(new_xor_sum, new_size);
                }
            }
            map = next_map;
        }
        return map;
    }

    const N = nums.length;
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    // Split the array into two halves for Meet-in-the-Middle
    const N_L = Math.floor(N / 2);
    const L = nums.slice(0, N_L);
    const R = nums.slice(N_L);

    // Step 1 & 2: Generate XOR sum maps for both halves
    const MapL = generate_xor_sums_map(L);
    const MapR = generate_xor_sums_map(R);

    let MaxKeptSize = -1;

    // Step 3: Combine results
    for (const [xL, sL] of MapL.entries()) {
        // We require xL ^ xR = target, so xR = target ^ xL
        const required_xR = target ^ xL;

        if (MapR.has(required_xR)) {
            const sR = MapR.get(required_xR);
            const current_kept_size = sL + sR;

            if (current_kept_size > MaxKeptSize) {
                MaxKeptSize = current_kept_size;
            }
        }
    }

    if (MaxKeptSize === -1) {
        // Target XOR sum is impossible to achieve
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum kept elements
        return N - MaxKeptSize;
    }
}

